function render(){
  const q=(document.getElementById('search')?.value||'').toLowerCase();
  // Filtre selon rechèch sèlman (pa type) pou grids yo
  const all=products.filter(p=>(`${p.title} ${p.cat} ${p.desc}`).toLowerCase().includes(q));
  // Chak seksyon montre pwodwi pa type — filtre tab cache seksyon men pa retire pwodwi
  document.getElementById('productGrid').innerHTML=all.filter(p=>p.type==='book').map(productCard).join('')||'<p class="small">Pa gen liv ki koresponn.</p>';
  document.getElementById('videoGrid').innerHTML=all.filter(p=>p.type==='video').map(productCard).join('')||'<p class="small">Pa gen fòmasyon video ki koresponn.</p>';
  document.getElementById('promptGrid').innerHTML=all.filter(p=>p.type==='prompt').map(productCard).join('')||'<p class="small">Pa gen prompt ki koresponn.</p>';
  document.getElementById('premiumGrid').innerHTML=all.filter(p=>p.type==='premium').map(productCard).join('')||'<p class="small">Pa gen aksè premium ki koresponn.</p>';
  // Montre/kache seksyon selon filtre aktif
  var sections={book:'livres',video:'formations',prompt:'prompts',premium:'premium'};
  ['livres','formations','prompts','premium'].forEach(function(id){
    var sec=document.getElementById(id);
    if(!sec) return;
    if(filter==='all') sec.style.display='';
    else sec.style.display=(sections[filter]===id)?'':'none';
  });
  updateCartCount();
  // Re-kalkile scroll spy apre chanjman
  if(window._navSpy) setTimeout(window._navSpy, 50);
}
function setFilter(f,el){
  filter=f;
  document.querySelectorAll('.chip').forEach(c=>c.classList.remove('active'));
  el.classList.add('active');
  render();
updateAuthUI();
  // Scroll sou premye seksyon ki vizib
  var target = f==='all' ? 'livres' : (f==='book'?'livres':f==='video'?'formations':f==='prompt'?'prompts':'premium');
  var sec = document.getElementById(target);
  if(sec) sec.scrollIntoView({behavior:'smooth'});
}
// BUG 7 FIX: detectCountry async — rezoud pwomès la avan chanyo ouvri
let userCountry = null;
let countryReady = false;
let countryCallbacks = [];
function onCountryReady(cb){if(countryReady){cb(userCountry)}else{countryCallbacks.push(cb)}}
(async function detectCountry(){
  try{
    const r=await fetch('https://ipapi.co/json/');
    const d=await r.json();
    userCountry=d.country_code||null;
  }catch(e){userCountry=null;}
  countryReady=true;
  countryCallbacks.forEach(cb=>cb(userCountry));
  countryCallbacks=[];
  if(document.getElementById('drawer')?.classList.contains('show')){renderCart();paypalRendered=false;loadPaypal();}
})();

// Tax flat: USA + Canada peye $2.99; lòt peyi $0
function taxableCountry(){return userCountry==='US'||userCountry==='CA'}
function taxAmount(sub){return sub>0&&taxableCountry()?2.99:0}
function taxCountryName(){return userCountry==='US'?'USA':userCountry==='CA'?'Canada':'lòt peyi'}
function grandTotal(){const sub=subtotal();return sub+taxAmount(sub)}
function subtotal(){return cart.reduce((s,i)=>{const p=itemData(i.id);return p?s+p.price*i.qty:s;},0)}

function save(){try{localStorage.setItem('kovax_cart',JSON.stringify(cart));}catch(e){}updateCartCount()}
function updateCartCount(){document.getElementById('cartCount').textContent=cart.reduce((a,i)=>a+i.qty,0)}
function addToCart(id){const p=products.find(x=>x.id===id);if(!p)return;const item=cart.find(x=>x.id===id);if(item)item.qty++;else cart.push({id,qty:1});save();openCart()}
function addBundle(){cart=cart.filter(i=>!['info','english','bundle'].includes(i.id));cart.push({id:'bundle',qty:1});save();openCart()}
// FIX: itemData retounen objè ki valid toujou — bundle pa gen download string 'bundle', li gen 2 fichye separe
function itemData(id){if(id==='bundle')return {id:'bundle',title:'Pake 2 Liv: Enfòmatik + Anglè',price:55,img:`data:image/svg+xml;base64,`,download:null,bundlePack:true};const p=products.find(p=>p.id===id);return p||null;}

