function removeItem(id){cart=cart.filter(i=>i.id!==id);save();renderCart();paypalRendered=false;loadPaypal()}
function changeQty(id,delta){const item=cart.find(i=>i.id===id);if(!item)return;item.qty+=delta;if(item.qty<=0){cart=cart.filter(i=>i.id!==id);}save();renderCart();paypalRendered=false;loadPaypal();}


function cartImage(p){
  const safeTitle = (p && p.title ? p.title : 'Kovax').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const iconMap={info:'💻',english:'📖','ai-video':'🤖',capcut:'🎬',prompts:'🎨',premium:'♛',bundle:'🎁'};
  const icon=iconMap[p.id]||'📦';
  if(p.img && !String(p.img).startsWith('assets/')) return p.img;
  const svg=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 300 300">
    <defs><linearGradient id="g" x1="0" x2="1" y1="0" y2="1"><stop stop-color="#2563ff"/><stop offset=".55" stop-color="#27c8ff"/><stop offset="1" stop-color="#8b5cf6"/></linearGradient><filter id="b"><feGaussianBlur stdDeviation="18"/></filter></defs>
    <rect width="300" height="300" rx="42" fill="#071126"/>
    <circle cx="68" cy="58" r="72" fill="#27c8ff" opacity=".25" filter="url(#b)"/>
    <circle cx="235" cy="240" r="82" fill="#8b5cf6" opacity=".28" filter="url(#b)"/>
    <rect x="34" y="34" width="232" height="232" rx="32" fill="url(#g)" opacity=".22" stroke="rgba(255,255,255,.36)"/>
    <text x="150" y="142" text-anchor="middle" font-size="76">${icon}</text>
    <text x="150" y="205" text-anchor="middle" font-family="Arial,sans-serif" font-size="24" font-weight="900" fill="white">KOVAX</text>
    <text x="150" y="234" text-anchor="middle" font-family="Arial,sans-serif" font-size="15" font-weight="700" fill="#a7f3ff">MARKET</text>
  </svg>`;
  return 'data:image/svg+xml;charset=UTF-8,'+encodeURIComponent(svg);
}

function renderCart(){
  const box=document.getElementById('cartItems');
  const checkoutBox=document.getElementById('checkoutBox');
  if(!cart.length){
    if(checkoutBox) checkoutBox.style.display='none';
    box.innerHTML=`<div style="text-align:center;padding:32px 16px 24px">
      <div style="font-size:52px;margin-bottom:14px;opacity:.7">🛒</div>
      <p style="font-weight:900;font-size:17px;margin-bottom:8px">Chanyo ou a vid!</p>
      <p class="small" style="margin-bottom:22px;line-height:1.6">Eksplore pwodwi yo epi klike sou<br><b style="color:var(--cyan)">🛒 Achte</b> pou ajoute yo.</p>
      <button onclick="closeCart();document.getElementById('livres').scrollIntoView({behavior:'smooth'})" style="display:inline-flex;align-items:center;gap:8px;background:linear-gradient(135deg,var(--blue),var(--cyan),var(--purple));border:0;border-radius:14px;color:#fff;padding:13px 22px;font:900 14px Outfit;cursor:pointer;transition:.2s" onmouseover="this.style.transform='translateY(-2px)'" onmouseout="this.style.transform=''">🛒 Eksplore Market la</button>
    </div>`;
    paypalRendered=false;
  }else{
    if(checkoutBox) checkoutBox.style.display='';
    // BUG 4 FIX: bouton qty + ak - pou chak pwodwi
    box.innerHTML=cart.map(i=>{
      const p=itemData(i.id);
      return `<div class="cartItem">
        <img src="${cartImage(p)}" alt="${p.title}" onerror="this.onerror=null;this.src=cartImage({id:'box',title:'Kovax'});">
        <div style="flex:1">
          <b>${p.title}</b><br>
          <small>${money(p.price)} × ${i.qty} = ${money(p.price*i.qty)}</small>
          <div style="display:flex;gap:6px;margin-top:6px;align-items:center">
            <button onclick="changeQty('${i.id}',-1)" style="border:1px solid rgba(255,255,255,.2);background:rgba(255,255,255,.07);color:#fff;border-radius:8px;width:28px;height:28px;cursor:pointer;font-size:16px;font-weight:900">−</button>
            <span style="font-weight:900;min-width:18px;text-align:center">${i.qty}</span>
            <button onclick="changeQty('${i.id}',1)" style="border:1px solid rgba(39,200,255,.3);background:rgba(39,200,255,.1);color:#27c8ff;border-radius:8px;width:28px;height:28px;cursor:pointer;font-size:16px;font-weight:900">+</button>
          </div>
        </div>
        <button class="remove" onclick="removeItem('${i.id}')">Retire</button>
      </div>`;
    }).join('');
  }
  const sub=subtotal();
  const tax=taxAmount(sub);
  const gt=sub+tax;
  const totalBox=document.getElementById('cartTotal');
  // Montre liy tax sèlman pou USA/Kanada
  const taxRow=document.getElementById('taxRow');
  const taxEl=document.getElementById('cartTax');
  const taxLabel=document.getElementById('taxLabel');
  if(taxRow){
    if(tax>0){
      taxRow.style.display='flex';
      if(taxLabel) taxLabel.textContent='Tax '+taxCountryName()+' ($2.99)';
      if(taxEl) taxEl.textContent=money(tax);
    } else {
      taxRow.style.display='none';
    }
  }
  if(totalBox) totalBox.textContent=money(gt);
  document.getElementById('success').classList.remove('show');
}

function loadPaypal(){
  const box=document.getElementById('paypal-button-container');
  // FIX #6: si chanyo vid, efase konteyner a sèlman — pa afiche mesaj.
  // checkoutBox kache dejà lè chanyo vid, donc nenpòt mesaj nan box la pa vizib epi parèt etranj.
  if(!cart.length){box.innerHTML='';return}
  // BUG 7 FIX: tann peyi avan afiche PayPal si li poko prè
  if(!countryReady){
    box.innerHTML='';
    onCountryReady(()=>{paypalRendered=false;loadPaypal();});
    return;
  }
  if(window.paypal){
    // BUG 3 FIX: rann sèlman si li pa deja rann
    if(!paypalRendered){renderPaypal();}
    return;
  }
  box.innerHTML='<p class="small">PayPal ap chaje...</p>';
  const s=document.createElement('script');
  s.src=`https://www.paypal.com/sdk/js?client-id=${PAYPAL_CLIENT_ID}&currency=USD&components=buttons&enable-funding=card&disable-funding=paylater`;
  s.onload=()=>{paypalRendered=false;renderPaypal();};
  s.onerror=()=>box.innerHTML='<p class="small">PayPal pa ka chaje kounya. Verifye internet oswa Client ID.</p>';
  document.body.appendChild(s);
}

function renderPaypal(){
  // BUG 3 FIX: pa rann si deja rann
  if(paypalRendered)return;
  const box=document.getElementById('paypal-button-container');
  box.innerHTML='';
  if(!window.paypal)return;
  paypal.Buttons({
    style:{layout:'vertical',shape:'pill',label:'pay'},
    createOrder:(data,actions)=>actions.order.create({purchase_units:[{description:'Kovax Market Products',amount:{currency_code:'USD',value:grandTotal().toFixed(2)}}]}),
    onApprove:(data,actions)=>actions.order.capture().then(unlockDownloads),
    onError:()=>box.innerHTML='<p class="small">Erè PayPal. Eseye ankò.</p>'
  }).render('#paypal-button-container');
  paypalRendered=true;
}

function unlockDownloads(){
  // Sove kòpi chanyo avan nou vide l
  const paidCart = [...cart];
  localStorage.setItem('kovax_paid_orders', JSON.stringify(paidCart));

  // Vide chanyo
  cart = [];
  save();
  paypalRendered = false;

  // Fèmen chanyo a
  document.getElementById('drawer').classList.remove('show');

  // Kache tout pwodwi yo + seksyon ki pa nesesè
  document.querySelector('main').style.display = 'none';

  // Montre paj konfirmasyon an plen
  let downloadLinks = '';
  paidCart.forEach(i => {
    const p = itemData(i.id);
    if(!p) return;
    if(p.bundlePack){
      downloadLinks += `
        <a class="dl-link" href="downloads/informatique-kovax-academy.pdf" download>
          <span class="dl-arrow">⬇</span>
          <div class="dl-info"><strong>Enfòmatik</strong><span>Klike pou telechaje PDF la</span></div>
        </a>
        <a class="dl-link" href="Ekri-pale-konprann-Kovax.pdf" download>
          <span class="dl-arrow">⬇</span>
          <div class="dl-info"><strong>Anglè</strong><span>Klike pou telechaje PDF la</span></div>
        </a>`;
    } else if(p.download){
      downloadLinks += `
        <a class="dl-link" href="${p.download}" download>
          <span class="dl-arrow">⬇</span>
          <div class="dl-info"><strong>${p.title}</strong><span>Klike pou telechaje fichye a</span></div>
        </a>`;
    } else {
      downloadLinks += `
        <a class="dl-link" href="${p.access||'#'}" target="_blank">
          <span class="dl-arrow" style="background:linear-gradient(135deg,var(--purple),var(--pink))">▶</span>
          <div class="dl-info"><strong>${p.title}</strong><span>Klike pou ouvri aksè ou a</span></div>
        </a>`;
    }
  });

  const confirmPage = document.createElement('div');
  confirmPage.id = 'confirmPage';
  confirmPage.innerHTML = `
    
    <div class="confirm-topbar">
      <a class="confirm-brand" href="#">
        <img class="confirm-brand-logo" src="data:image/png;base64," alt="Kovax" onerror="this.style.display='none';this.nextElementSibling.style.display='block'">
        <span class="confirm-brand-emoji" style="display:none">🏆</span>
        <b>KOVAX <span>ACADEMY</span></b>
      </a>
      <div style="font-size:13px;font-weight:700;color:var(--muted)">✅ Acha Konfime</div>
    </div>
    <div class="confirm-body">
    <div class="confirm-card">
      <span class="confirm-icon">🎉</span>
      <div class="confirm-title">Pèman Konfime!</div>
      <p class="confirm-msg">Mèsi pou acha ou a. Klike sou bouton ki pi ba yo pou telechaje oswa ouvri pwodwi ou yo.</p>
      ${downloadLinks}
      <button class="back-btn" onclick="document.getElementById('confirmPage').remove();document.querySelector('main').style.display='';filter='all';document.querySelectorAll('.chip').forEach((c,i)=>c.classList.toggle('active',i===0));window.scrollTo({top:0,behavior:'smooth'});render();">← Retounen sou Market la</button>
    </div>
    </div>`;
  document.body.appendChild(confirmPage);
}
