// Scroll spy — bouton nav ble selon seksyon ou ye
(function(){
  var sections = [
    {id:'market',    navId:'nav-market'},
    {id:'livres',    navId:'nav-liv'},
    {id:'formations',navId:'nav-form'},
    {id:'prompts',   navId:'nav-prompt'},
    {id:'premium',   navId:'nav-premium'}
  ];
  function getTop(el){
    // Kalkile pozisyon absolye yon eleman depi tet paj la
    var top = 0;
    while(el){ top += el.offsetTop; el = el.offsetParent; }
    return top;
  }
  function setActive(navId){
    document.querySelectorAll('.nav a').forEach(function(x){ x.classList.remove('active'); });
    var el = document.getElementById(navId);
    if(el) el.classList.add('active');
  }
  function onScroll(){
    var scrollY = window.scrollY + 160;
    var current = 'nav-market';
    for(var i = 0; i < sections.length; i++){
      var el = document.getElementById(sections[i].id);
      // Sote seksyon kache yo
      if(!el || el.style.display === 'none') continue;
      if(scrollY >= getTop(el)){
        current = sections[i].navId;
      }
    }
    setActive(current);
  }
  window.addEventListener('scroll', onScroll, {passive:true});
  // Re-kalkile apre render() kache/montre seksyon
  window._navSpy = onScroll;
  onScroll();
})();

